CREATE TABLE IF NOT EXISTS fq_jobs (id VARCHAR(36) PRIMARY KEY, name VARCHAR(200) NOT NULL, created_by INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS fq_job_items (id VARCHAR(36) PRIMARY KEY, job_id VARCHAR(36) NOT NULL, name VARCHAR(200) NOT NULL, cost DECIMAL(10,2) NOT NULL DEFAULT 0, paid_by VARCHAR(50) NOT NULL DEFAULT 'Phil123', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (job_id) REFERENCES fq_jobs(id) ON DELETE CASCADE);